mapper.select:
SELECT COUNT(*)
FROM award_application


        AND application_status = #{status}

SELECT COUNT(*) FROM award_application aa LEFT JOIN student s ON aa.student_id = s.student_id LEFT JOIN competition c ON aa.competition_id = c.competition_id
AND aa.application_status = #{status}
AND c.competition_name LIKE CONCAT('%', #{competitionName}, '%')
AND s.student_number = #{studentNumber}

SELECT aa.application_id as applicationId, aa.application_number as applicationNumber, aa.project_name as projectName, aa.competition_level as competitionLevel, aa.award_rank as awardRank, aa.award_level as awardLevel, aa.award_time as awardTime, aa.application_status as applicationStatus, aa.create_time as createTime, s.student_number as studentNumber, s.student_name as studentName, c.competition_name as competitionName FROM award_application aa LEFT JOIN student s ON aa.student_id = s.student_id LEFT JOIN competition c ON aa.competition_id = c.competition_id
AND aa.application_status = #{status}
AND c.competition_name LIKE CONCAT('%', #{competitionName}, '%')
AND s.student_number = #{studentNumber}
ORDER BY CASE aa.application_status WHEN 'pending' THEN 1 WHEN 'returned' THEN 2 WHEN 'approved' THEN 3 WHEN 'rejected' THEN 4 ELSE 5 END, aa.create_time DESC LIMIT #{offset}, #{pageSize}

